 1	import * as React from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { useNavigate } from 'react-router-dom-v5-compat';
 4	
 5	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Button, Stack, StackItem } from '@patternfly/react-core';
 8	
 9	export const WizardNoBootModal: React.VFC<{
10	  isOpen: boolean;
11	  namespace: string;
12	  onClose: () => void;
13	  onSubmit: () => Promise<void>;
14	}> = ({ isOpen, namespace, onClose, onSubmit }) => {
15	  const { t } = useKubevirtTranslation();
16	  const navigate = useNavigate();
17	
18	  const goToDisksTab = () => {
19	    onClose();
20	    navigate(`/k8s/ns/${namespace}/catalog/template/review/disks`);
21	  };
22	
23	  return (
24	    <TabModal
25	      headerText={t('No available boot source')}
26	      isOpen={isOpen}
27	      obj={null}
28	      onClose={onClose}
29	      onSubmit={onSubmit}
30	      positionTop={false}
31	      submitBtnText={t('Create with no available boot source')}
32	      titleIconVariant="warning"
33	    >
34	      <Stack hasGutter>
35	        <StackItem>
36	          <p>
37	            {t(
38	              'The VirtualMachine you are creating does not have an available boot source. We recommended that you select a boot source to create the VirtualMachine.',
39	            )}
40	          </p>
41	        </StackItem>
42	        <StackItem>
43	          <Trans ns="plugin__kubevirt-plugin">
44	            You can select the boot source in the{' '}
45	            <Button isInline onClick={goToDisksTab} variant="link">
46	              Disks
47	            </Button>{' '}
48	            tab.
49	          </Trans>
50	        </StackItem>
51	      </Stack>
52	    </TabModal>
53	  );
54	};

